thon tensorflow_datasets 'numpy<2'\n","\n"]},{"output_type":"stream","name":"stdout","text":["Using virtual environment 'r-keras' ...\n"]},{"output_type":"stream","name":"stderr","text":["+ /root/.virtualenvs/r-keras/bin/python -m pip install --upgrade --no-user tensorflow-cpu\n","\n"]},{"output_type":"stream","name":"stdout","text":["Using virtual environment 'r-keras' ...\n"]},{"output_type":"stream","name":"stderr","text":["+ /root/.virtualenvs/r-keras/bin/python -m pip install --upgrade --no-user 'keras==3.*'\n","\n","Finished installing Keras!\n","\n"]},{"output_type":"stream","name":"stdout","text":["Predicted Labels:\n","[1] 9 2\n","\n","Actual Labels:\n","[1] 9 2\n"]}],"source":["# 1. Setup - Run this first (only once)\n","install.packages(\"keras3\")\n","library(keras3)\n","\n","# Install a suitable Python version (e.g., 3.10 to match Keras's typical requirements)\n","reticulate::install_python(version = \"3.10\")\n","\n","# Install Keras + TensorFlow backend (run this once)\n","install_keras(backend = \"tensorflow\", restart_session = TRUE)\n","\n","# 2. Load Data\n","fashion <- dataset_fashion_mnist()\n","\n","# 3. Preprocess - Important fix here\n","train_x <- array_reshape(fashion$train$x / 255, c(60000, 28, 28, 1))\n","test_x  <- array_reshape(fashion$test$x / 255,  c(10000, 28, 28, 1))\n","\n","train_y <- fashion$train$y\n","test_y  <- fashion$test$y\n","\n","# 4. Define the 6-Layer CNN (exactly as i want)\n","model <- keras_model_sequential() %>%\n","  layer_conv_2d(filters = 32, kernel_size = c(3,3), activation = \"relu\",\n","                input_shape = c(28, 28, 1)) %>%     # Layer 1\n","  layer_max_pooling_2d(pool_size = c(2,2)) %>%      # Layer 2\n","  layer_conv_2d(filters = 64, kernel_size = c(3,3), activation = \"relu\") %>%  # Layer 3\n","  layer_flatten() %>%                               # Layer 4\n","  layer_dense(units = 128, activation = \"relu\") %>% # Layer 5\n","  layer_dense(units = 10, activation = \"softmax\")   # Layer 6\n","\n","# 5. Compile\n","model %>% compile(\n","  optimizer = \"adam\",\n","  loss = \"sparse_categorical_crossentropy\",\n","  metrics = \"accuracy\"\n",")\n","\n","# 6. Train (this may take a few minutes)\n","model %>% fit(\n","  train_x, train_y,\n","  epochs = 5,\n","  batch_size = 32,\n","  validation_split = 0.1,\n","  verbose = 1\n",")\n","\n","# 7. Predict on the first two test images\n","images_to_predict <- test_x[1:2, , , , drop = FALSE]\n","\n","predictions <- model %>% predict(images_to_predict)\n","\n","# Convert probabilities to class labels (0-9)\n","predicted_classes <- apply(predictions, 1, which.max) - 1\n","\n","cat(\"Predicted Labels:\\n\")\n","print(predicted_classes)\n","\n","cat(\"\\nActual Labels:\\n\")\n","print(test_y[1:2])"]}],"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPFpY8SF+xD1ZO72U/dOGL0"},"kernelspec":{"display_name":"R","name":"ir"},"language_info":{"name":"R"}},"nbformat":4,"nbformat_minor":0}